  CREATE DATABASE bwapp CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
  GRANT ALL PRIVILEGES ON bwapp.* TO 'bwapp'@'localhost';
  FLUSH PRIVILEGES;
  SHOW GRANTS FOR 'bwapp'@'localhost';
" 2>&1
echo ""
