SD php -r '
  $_SERVER["REQUEST_METHOD"] = "POST";
  $_POST["install"] = "yes";
  ob_start();
  include "/var/www/html/bwapp/install.php";
  $x = ob_get_clean();
  echo "[PHP install.php output LEN=".strlen($x)."]\n";
  echo substr($x, 0, 400);
' 2>&1
echo ""
